# Generated by KernelGen: https://github.com/flagos-ai/KernelGen
import pytest
import torch

from . import base

# Hardcoded shapes: _euclidean_dist requires (N,D) matrix pairs;
# CI --level core overrides GenericBenchmark shapes with 1D/3D defaults,
# so we use a custom Benchmark subclass with set_shapes override.
EUCLIDEAN_DIST_SHAPES = [
    ((64, 128), (64, 128)),
    ((128, 256), (128, 256)),
]


class EuclideanDistBenchmark(base.Benchmark):
    def set_shapes(self, shape_file_path=None):
        self.shapes = EUCLIDEAN_DIST_SHAPES

    def get_input_iter(self, cur_dtype):
        for (n1, d), (n2, d2) in self.shapes:
            x1 = torch.randn(n1, d, dtype=cur_dtype, device=self.device)
            x2 = torch.randn(n2, d2, dtype=cur_dtype, device=self.device)
            yield x1, x2


@pytest.mark.euclidean_dist
def test_euclidean_dist():
    bench = EuclideanDistBenchmark(
        op_name="euclidean_dist",
        torch_op=torch._euclidean_dist,
        # cdist_cuda does not support Half/BFloat16
        dtypes=[torch.float32],
    )
    bench.run()
